using System;

class Program
{
    static void Main(string[] args)
    {
        int number = 10;
        int divisor = 0;

        try
        {
            int result = number / divisor;
            Console.WriteLine($"Nəticə: {result}");
        }
        catch (DivideByZeroException ex)
        {
            Console.WriteLine("Səhv: Sıfıra bölmək olmaz!");
            Console.WriteLine($"Səhv mesajı: {ex.Message}");
        }
    }
}
// Output:
// Səhv: Sıfıra bölmək olmaz!
// Səhv mesajı: Attempted to divide by zero.

